@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"
          placeholder="Type your notes here..."></textarea>

<div class="d-flex align-items-center gap-2 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted ms-2">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;
    private DotNetObjectReference<Notepad>? dotNetRef;

    private const string StorageKeyContent = "notepad-content";
    private const string StorageKeyTimestamp = "notepad-timestamp";

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/Pages/Notepad.razor.js");

        // Restore saved content
        var stored = await module.InvokeAsync<string?>("getItem", StorageKeyContent);
        if (!string.IsNullOrEmpty(stored))
        {
            content = stored;
            savedContent = stored;

            var ts = await module.InvokeAsync<string?>("getItem", StorageKeyTimestamp);
            if (DateTime.TryParse(ts, out var parsed))
                lastSavedAt = parsed;

            StateHasChanged();
        }

        // Wire up beforeunload guard
        dotNetRef = DotNetObjectReference.Create(this);
        await module.InvokeVoidAsync("registerBeforeUnload", dotNetRef);

        // Auto-save every 30 seconds
        autoSaveTimer = new System.Threading.Timer(
            async _ => await InvokeAsync(AutoSaveAsync),
            null,
            TimeSpan.FromSeconds(30),
            TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public bool GetHasUnsavedChanges() => HasUnsavedChanges;

    private async Task AutoSaveAsync()
    {
        if (HasUnsavedChanges)
            await SaveAsync();
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("setItem", StorageKeyContent, content);
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("setItem", StorageKeyTimestamp, lastSavedAt.Value.ToString("o"));
        savedContent = content;
        StateHasChanged();
    }

    private async Task ClearAsync()
    {
        if (module is null) return;

        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        await module.InvokeVoidAsync("removeItem", StorageKeyContent);
        await module.InvokeVoidAsync("removeItem", StorageKeyTimestamp);
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
            await autoSaveTimer.DisposeAsync();

        if (module is not null)
        {
            await module.InvokeVoidAsync("unregisterBeforeUnload");
            await module.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

let _dotNetRef = null;

function _beforeUnloadHandler(e) {
    if (_dotNetRef) {
        // Synchronous JS interop isn't possible, so we check via a flag pattern.
        // Instead, we use the synchronous DotNet invocation.
        const hasChanges = _dotNetRef.invokeMethod("GetHasUnsavedChanges");
        if (hasChanges) {
            e.preventDefault();
        }
    }
}

export function registerBeforeUnload(dotNetRef) {
    _dotNetRef = dotNetRef;
    window.addEventListener("beforeunload", _beforeUnloadHandler);
}

export function unregisterBeforeUnload() {
    window.removeEventListener("beforeunload", _beforeUnloadHandler);
    _dotNetRef = null;
}

export function getItem(key) {
    return localStorage.getItem(key);
}

export function setItem(key, value) {
    localStorage.setItem(key, value);
}

export function removeItem(key) {
    localStorage.removeItem(key);
}

